<script setup lang="ts">import { computed, ref } from 'vue'; import { useRouter } from 'vue-router'; import { Check, ChevronLeft, ChevronRight, Download, FolderOpen, LockKeyhole } from '@lucide/vue'; import { api } from '../api/client'; import AsyncButton from '../components/AsyncButton.vue'; import { useAsyncActions } from '../composables/useAsyncActions'; import { useSessionStore } from '../stores/session'; const router=useRouter(),session=useSessionStore(),actions=useAsyncActions(); const step=ref(1),error=ref(''); const form=ref({new_password:'',confirm_password:'',qb_mode:'managed',qb_url:'',qb_username:'',qb_password:'',base_download_dir:''}); const steps=[{title:'账户安全',icon:LockKeyhole},{title:'下载器',icon:Download},{title:'媒体目录',icon:FolderOpen}]; const canNext=computed(()=>step.value===1?form.value.new_password.length>=8&&form.value.new_password===form.value.confirm_password:step.value===2?(form.value.qb_mode==='managed'||Boolean(form.value.qb_url)):true); async function chooseDir(){error.value='';try{await actions.run('choose-directory',async()=>{const r=await api<{path:string}>('/system/pick-directory',{method:'POST',body:JSON.stringify({title:'选择媒体目录',default_path:form.value.base_download_dir}),headers:{'Content-Type':'application/json'}});if(r.path)form.value.base_download_dir=r.path})}catch(e){error.value=e instanceof Error?e.message:'无法选择目录'}} async function finish(){error.value='';try{await actions.run('finish',async()=>{await api('/setup/bootstrap',{method:'POST',body:JSON.stringify(form.value),headers:{'Content-Type':'application/json'}});await session.load(true);await router.push('/')})}catch(e){error.value=e instanceof Error?e.message:'初始化失败'}}</script>
<template><div class="page-grid"><section class="overflow-hidden rounded-[1.75rem] bg-gradient-to-r from-rose-500 to-pink-600 p-6 text-white shadow-xl sm:p-9"><p class="text-xs font-black uppercase tracking-[.15em] text-white/75">首次启动</p><h2 class="mt-2 text-3xl font-black sm:text-4xl">三步完成初始化</h2><p class="mt-3 max-w-2xl text-sm leading-6 text-white/85">先保护管理员账户，再连接下载器并选定媒体目录。以后都可以在设置中修改。</p></section><div class="grid gap-5 lg:grid-cols-[280px_1fr]"><aside class="panel p-4"><ol class="space-y-2"><li v-for="(item,i) in steps" :key="item.title" class="flex min-h-14 items-center gap-3 rounded-xl px-3" :class="step===i+1?'bg-[var(--brand-soft)] text-[var(--brand-strong)]':''"><span class="grid h-9 w-9 place-items-center rounded-xl" :class="step>i+1?'bg-[var(--success)] text-white':'bg-[var(--surface-muted)]'"><Check v-if="step>i+1" :size="17"/><component :is="item.icon" v-else :size="17"/></span><span><small class="muted block">步骤 {{ i+1 }}</small><strong>{{ item.title }}</strong></span></li></ol></aside><section class="panel p-5 sm:p-8"><form @submit.prevent="step<3?step++:finish()"><div v-if="step===1" class="space-y-5"><div><p class="eyebrow">账户安全</p><h3 class="mt-2 text-2xl font-black">设置新的管理员密码</h3></div><label class="label">新密码<input v-model="form.new_password" class="field" type="password" minlength="8" required/><span class="text-xs font-normal">至少 8 个字符</span></label><label class="label">确认密码<input v-model="form.confirm_password" class="field" type="password" minlength="8" required/></label></div><div v-else-if="step===2" class="space-y-5"><div><p class="eyebrow">下载器</p><h3 class="mt-2 text-2xl font-black">连接 qBittorrent</h3></div><div class="grid gap-3 sm:grid-cols-2"><button type="button" class="panel-muted min-h-24 p-4 text-left" :class="form.qb_mode==='managed'?'ring-2 ring-[var(--brand)]':''" @click="form.qb_mode='managed'"><strong class="block">内置托管</strong><span class="muted text-sm">自动使用本机 qBittorrent</span></button><button type="button" class="panel-muted min-h-24 p-4 text-left" :class="form.qb_mode==='external'?'ring-2 ring-[var(--brand)]':''" @click="form.qb_mode='external'"><strong class="block">外部服务</strong><span class="muted text-sm">连接已有 Web UI</span></button></div><template v-if="form.qb_mode==='external'"><label class="label">Web UI 地址<input v-model="form.qb_url" class="field" placeholder="http://127.0.0.1:8080"/></label><div class="grid gap-4 sm:grid-cols-2"><label class="label">用户名<input v-model="form.qb_username" class="field"/></label><label class="label">密码<input v-model="form.qb_password" class="field" type="password"/></label></div></template></div><div v-else class="space-y-5"><div><p class="eyebrow">媒体目录</p><h3 class="mt-2 text-2xl font-black">你的番剧存放在哪里？</h3></div><label class="label">基础下载目录<div class="flex gap-2"><input v-model="form.base_download_dir" class="field" placeholder="可稍后设置"/><AsyncButton class="btn btn-secondary shrink-0" :loading="actions.isBusy('choose-directory')" loading-label="选择中…" @click="chooseDir"><FolderOpen :size="17"/>选择</AsyncButton></div></label><div class="panel-muted p-4 text-sm leading-6 muted">初始化不会移动已有文件。首次扫描会读取目录并建立本地媒体索引。</div></div><p v-if="error" role="alert" class="mt-5 text-sm font-bold text-[var(--danger)]">{{ error }}</p><div class="mt-8 flex justify-between"><button type="button" class="btn btn-secondary" :disabled="step===1||actions.isBusy('finish')" @click="step--"><ChevronLeft :size="17"/>上一步</button><AsyncButton type="submit" class="btn btn-primary" :disabled="!canNext" :loading="actions.isBusy('finish')" loading-label="正在完成…">{{ step===3?'完成初始化':'下一步' }}<ChevronRight v-if="step<3" :size="17"/></AsyncButton></div></form></section></div></div></template>
